from enum import Enum
from dataclasses import dataclass, field
import hashlib

class FlagStage(Enum):
    OFF = "off"
    INTERNAL = "internal"   # team + QA only
    CANARY = "canary"       # 1–5% of users
    GRADUATED = "graduated" # 10–50–100% ramp
    GA = "ga"               # 100%, flag to be removed

@dataclass
class AIFeatureFlag:
    name: str
    stage: FlagStage
    canary_pct: float = 0.0          # 0.0–1.0
    internal_user_ids: set = field(default_factory=set)
    # Separate prompt configs per code path
    control_prompt: str = ""
    treatment_prompt: str = ""

    def is_enabled_for(self, user_id: str) -> bool:
        if self.stage == FlagStage.OFF:
            return False
        if self.stage == FlagStage.GA:
            return True
        if self.stage == FlagStage.INTERNAL:
            return user_id in self.internal_user_ids
        # Canary / Graduated: deterministic bucket by user_id hash
        bucket = int(hashlib.md5(f"{self.name}:{user_id}".encode()).hexdigest(), 16) % 100
        return bucket < int(self.canary_pct * 100)

    def prompt_for(self, user_id: str) -> str:
        return self.treatment_prompt if self.is_enabled_for(user_id) else self.control_prompt

import os, json
from functools import lru_cache

@lru_cache(maxsize=None)
def _load_flag_config() -> dict:
    """Load flag config from environment or a config file."""
    raw = os.environ.get("AI_FEATURE_FLAGS", "{}")
    return json.loads(raw)

class FlagRegistry:
    def __init__(self):
        self._flags: dict[str, AIFeatureFlag] = {}

    def register(self, flag: AIFeatureFlag) -> None:
        self._flags[flag.name] = flag

    def get(self, name: str) -> AIFeatureFlag:
        flag = self._flags[name]
        # Allow runtime override from env/config without redeploy
        overrides = _load_flag_config().get(name, {})
        if "stage" in overrides:
            flag = AIFeatureFlag(
                name=flag.name,
                stage=FlagStage(overrides["stage"]),
                canary_pct=overrides.get("canary_pct", flag.canary_pct),
                internal_user_ids=flag.internal_user_ids,
                control_prompt=flag.control_prompt,
                treatment_prompt=flag.treatment_prompt,
            )
        return flag

flag_registry = FlagRegistry()

# Register flags at application startup
flag_registry.register(AIFeatureFlag(
    name="improved-date-extraction",
    stage=FlagStage.CANARY,
    canary_pct=0.05,
    control_prompt="Extract dates from the user's message.",
    treatment_prompt="Extract dates from the user's message. Always return dates in ISO 8601 format (YYYY-MM-DD). If the year is ambiguous, prefer the future date.",
))

