import sys, json
from feature_flags import FlagRegistry, FlagStage

GATES = {
    FlagStage.CANARY: {
        "min_pass_rate": 0.90,
        "max_regression_pp": 2.0,     # ≤2 percentage points drop
        "required_hours": 24,          # must hold for 24h before advancing
    },
    FlagStage.GRADUATED: {
        "min_pass_rate": 0.92,
        "max_regression_pp": 1.0,
        "required_hours": 24,
    },
}

def load_metrics(flag_name: str, variant: str) -> dict:
    """Load eval metrics from your observability store."""
    # Implementation depends on your metrics backend
    raise NotImplementedError

def check_gate(flag_name: str) -> bool:
    registry = FlagRegistry()
    flag = registry.get(flag_name)
    gate = GATES.get(flag.stage)
    if not gate:
        print(f"No gate defined for stage {flag.stage.value} — manual review required")
        return False

    control = load_metrics(flag_name, "control")
    treatment = load_metrics(flag_name, "treatment")

    pass_rate = treatment["pass_rate"]
    regression = control["pass_rate"] - pass_rate

    ok = pass_rate >= gate["min_pass_rate"] and regression <= gate["max_regression_pp"] / 100
    if not ok:
        print(f"GATE FAIL: pass_rate={pass_rate:.2%}, regression={regression:.2%}")
    else:
        print(f"GATE PASS: pass_rate={pass_rate:.2%}, regression={regression:.2%}")
    return ok

if __name__ == "__main__":
    flag_name = sys.argv[1]
    sys.exit(0 if check_gate(flag_name) else 1)

