from dataclasses import dataclass

@dataclass
class RequestContext:
    """Passed through every agent call in the chain."""
    user_id: str
    active_flags: dict[str, bool]  # flag_name -> is_treatment

def build_context(user_id: str) -> RequestContext:
    """Evaluate all flags once at the request boundary."""
    from feature_flags import flag_registry
    active = {}
    for flag_name in ["improved-retrieval", "new-generation-prompt", "web-search-tool"]:
        flag = flag_registry.get(flag_name)
        active[flag_name] = flag.is_enabled_for(user_id)
    return RequestContext(user_id=user_id, active_flags=active)

